#define UNIONIZED 0
#define NUCLIDE 1
#define HASH 2

typedef struct{
	double energy;
	double total_xs;
	double elastic_xs;
	double absorbtion_xs;
	double fission_xs;
	double nu_fission_xs;
} NuclideGridPoint;

typedef struct{
	int nthreads;
	long n_isotopes;
	long n_gridpoints;
	int lookups;
	char * HM;
	int grid_type; 
	int hash_bins;
	int particles;
	int simulation_method;
	int binary_mode;
	int kernel_id;
	int platform_id;
	int device_id;
} Inputs;

long grid_search_nuclide_kernel( long n, double quarry, const NuclideGridPoint * A, long low, long high)
{
	long lowerLimit = low;
	long upperLimit = high;
	long examinationPoint;
	long length = upperLimit - lowerLimit;

	while( length > 1 )
	{
		examinationPoint = lowerLimit + ( length / 2 );

		if( A[examinationPoint].energy > quarry )
			upperLimit = examinationPoint;
		else
			lowerLimit = examinationPoint;

		length = upperLimit - lowerLimit;
	}

	return lowerLimit;
}

long grid_search_kernel( long n, double quarry, const double * A)
{
	long lowerLimit = 0;
	long upperLimit = n-1;
	long examinationPoint;
	long length = upperLimit - lowerLimit;

	while( length > 1 )
	{
		examinationPoint = lowerLimit + ( length / 2 );

		if( A[examinationPoint] > quarry )
			upperLimit = examinationPoint;
		else
			lowerLimit = examinationPoint;

		length = upperLimit - lowerLimit;
	}

	return lowerLimit;
}

void calculate_micro_xs_kernel(   double p_energy, int nuc, long n_isotopes,
                           long n_gridpoints,
                           const double * egrid, const int * index_data,
                           const NuclideGridPoint * nuclide_grids,
                           long idx, double * xs_vector, int grid_type, int hash_bins ){

	double f;
	NuclideGridPoint low; 
	NuclideGridPoint high;

	int idx_low = 0;
	int idx_high = 0;

	if( grid_type == NUCLIDE )
	{
		idx_low = grid_search_nuclide_kernel( n_gridpoints, p_energy, &nuclide_grids[nuc*n_gridpoints], 0, n_gridpoints-1);
		if( idx_low == n_gridpoints - 1 )
			idx_low = idx_low - 1;

		idx_high = idx_low + 1;
		low = nuclide_grids[nuc*n_gridpoints + idx_low];
		high = nuclide_grids[nuc*n_gridpoints + idx_high];
	}
	else if( grid_type == UNIONIZED) 
	{
		idx_low = index_data[idx * n_isotopes + nuc];
		if( idx_low == n_gridpoints - 1 )
			idx_low = idx_low - 1;

		idx_high = idx_low + 1;
		low = nuclide_grids[nuc*n_gridpoints + idx_low];
		high = nuclide_grids[nuc*n_gridpoints + idx_high];
	}
	else 
	{
		int u_low = index_data[idx * n_isotopes + nuc];
		int u_high;
		if( idx == hash_bins - 1 )
			u_high = n_gridpoints - 1;
		else
			u_high = index_data[(idx+1)*n_isotopes + nuc] + 1;

		double e_low  = nuclide_grids[nuc*n_gridpoints + u_low].energy;
		double e_high = nuclide_grids[nuc*n_gridpoints + u_high].energy;
		int lower;
		if( p_energy <= e_low )
			lower = 0;
		else if( p_energy >= e_high )
			lower = n_gridpoints - 1;
		else
			lower = grid_search_nuclide_kernel( n_gridpoints, p_energy, &nuclide_grids[nuc*n_gridpoints], u_low, u_high);

		if( lower == n_gridpoints - 1 )
			lower = lower - 1;

		idx_low = lower;
		idx_high = idx_low + 1;
		low = nuclide_grids[nuc*n_gridpoints + idx_low];
		high = nuclide_grids[nuc*n_gridpoints + idx_high];
	}

	f = (high.energy - p_energy) / (high.energy - low.energy);

	xs_vector[0] = high.total_xs - f * (high.total_xs - low.total_xs);
	xs_vector[1] = high.elastic_xs - f * (high.elastic_xs - low.elastic_xs);
	xs_vector[2] = high.absorbtion_xs - f * (high.absorbtion_xs - low.absorbtion_xs);
	xs_vector[3] = high.fission_xs - f * (high.fission_xs - low.fission_xs);
	xs_vector[4] = high.nu_fission_xs - f * (high.nu_fission_xs - low.nu_fission_xs);
}

void calculate_macro_xs_kernel( double p_energy, int mat, long n_isotopes,
                         long n_gridpoints, const int * num_nucs,
                         const double * concs,
                         const double * egrid, const int * index_data,
                         const NuclideGridPoint * nuclide_grids,
                         const int * mats,
                         double * macro_xs_vector, int grid_type, int hash_bins, int max_num_nucs ){
	int p_nuc; 
	long idx = -1;	
	double conc; 

	for( int k = 0; k < 5; k++ )
		macro_xs_vector[k] = 0.0;

	if( grid_type == UNIONIZED )
		idx = grid_search_kernel( n_isotopes * n_gridpoints, p_energy, egrid);	
	else if( grid_type == HASH )
	{
		double du = 1.0 / hash_bins;
		idx = (long)(p_energy / du);
	}

	for( int j = 0; j < num_nucs[mat]; j++ )
	{
		double xs_vector[5];
		p_nuc = mats[mat*max_num_nucs + j];
		conc = concs[mat*max_num_nucs + j];
		calculate_micro_xs_kernel( p_energy, p_nuc, n_isotopes,
		                    n_gridpoints, egrid, index_data,
		                    nuclide_grids, idx, xs_vector, grid_type, hash_bins );
		for( int k = 0; k < 5; k++ )
			macro_xs_vector[k] += xs_vector[k] * conc;
	}
}

__kernel void macro_xs_lookup_kernel( Inputs in, int max_num_nucs, 
                                      __global const int * num_nucs,
                                      __global const double * concs,
                                      __global const double * unionized_energy_array,
                                      __global const int * index_grid,
                                      __global const NuclideGridPoint * nuclide_grid,
                                      __global const int * mats,
                                      __global int * verification_array )
{
	int i = get_global_id(0);

	if( i >= in.lookups )
		return;

	unsigned long seed = 1070ULL;
	const unsigned long m = 9223372036854775808ULL; 
	const unsigned long a = 2806196910506780709ULL;
	const unsigned long c = 1ULL;

	unsigned long n = 2 * (unsigned long)i;
	unsigned long a_new = 1;
	unsigned long c_new = 0;
	while(n > 0) 
	{
		if(n & 1)
		{
			a_new *= a;
			c_new = c_new * a + c;
		}
		c *= (a + 1);
		a *= a;
		n >>= 1;
	}
	seed = (a_new * seed + c_new) % m;

	double p_energy = (double)seed / (double)m;

	seed = (a * seed + c) % m;
	double roll = (double)seed / (double)m;

	double dist[12];
	dist[0]  = 0.140;	
	dist[1]  = 0.052;	
	dist[2]  = 0.275;	
	dist[3]  = 0.134;	
	dist[4]  = 0.154;	
	dist[5]  = 0.064;	
	dist[6]  = 0.066;	
	dist[7]  = 0.055;	
	dist[8]  = 0.008;	
	dist[9]  = 0.015;	
	dist[10] = 0.025;	
	dist[11] = 0.013;

	int mat = 0;
	for( int k = 0; k < 12; k++ )
	{
		double running = 0;
		for( int j = k; j > 0; j-- )
			running += dist[j];
		if( roll < running )
		{
			mat = k;
			break;
		}
	}

	double macro_xs_vector[5];

	calculate_macro_xs_kernel(
			p_energy,        
			mat,             
			in.n_isotopes,   
			in.n_gridpoints, 
			num_nucs,     
			concs,        
			unionized_energy_array, 
			index_grid,   
			nuclide_grid, 
			mats,         
			macro_xs_vector, 
			in.grid_type,    
			in.hash_bins,    
			max_num_nucs  
			);

	double max = -1.0;
	int max_idx = 0;
	for(int j = 0; j < 5; j++ )
	{
		if( macro_xs_vector[j] > max )
		{
			max = macro_xs_vector[j];
			max_idx = j;
		}
	}

	verification_array[i] = max_idx + 1;
}
